import fs from 'fs';
import path from 'path';

/**
 * Generates an auth module based on the auth contract.
 */
export function generateAuth(contract, outPath) {
  let code = `// Generated by Fe compiler
// Source: auth contract
// DO NOT EDIT.

export class AuthProvider {
  constructor() {
    this.token = null;
    this.isHydrating = true;
    this.listeners = new Set();
    this.storageKey = '${contract.config.tokenKey || 'fe_auth_token'}';
  }

  async hydrate() {
    this.isHydrating = true;
    try {
      const saved = ${contract.config.tokenStorage === 'localStorage' ? `typeof window !== 'undefined' ? window.localStorage.getItem(this.storageKey) : null` : `null`};
      if (saved) {
        this.token = saved;
      }
    } catch(e) {}
    this.isHydrating = false;
    this._notify();
  }

  async login(token) {
    this.token = token;
    try {
      ${contract.config.tokenStorage === 'localStorage' ? `if (typeof window !== 'undefined') window.localStorage.setItem(this.storageKey, token);` : ``}
    } catch(e) {}
    this._notify();
    return true;
  }

  async logout() {
    this.token = null;
    try {
      ${contract.config.tokenStorage === 'localStorage' ? `if (typeof window !== 'undefined') window.localStorage.removeItem(this.storageKey);` : ``}
    } catch(e) {}
    this._notify();
    return true;
  }

  getToken() {
    return this.token;
  }

  isAuthenticated() {
    return !!this.token;
  }

  onAuthStateChanged(cb) {
    this.listeners.add(cb);
    cb(this.isAuthenticated());
    return () => this.listeners.delete(cb);
  }

  _notify() {
    this.listeners.forEach(cb => cb(this.isAuthenticated()));
  }

  routeGuard(path, routeDef) {
    const isAuth = this.isAuthenticated();
    // Default zero-trust if no rule specified, except for login
    let requiresAuth = true;
    
    ${Object.entries(contract.routes || {}).map(([route, def]) => {
      if (def.roles && def.roles.includes('guest')) {
        return `if (path === '${route}') requiresAuth = false;`;
      }
      return ``;
    }).join('\n    ')}
    
    if (requiresAuth && !isAuth) {
      return '${contract.config.loginPath || '/login'}';
    }
    return true; // proceed
  }
}

export const globalAuthProvider = new AuthProvider();
`;

  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  fs.writeFileSync(outPath, code, 'utf8');
  console.log('Generated:', outPath);
}

function runCLI() {
  const contractPath = process.argv[2] || 'contracts/auth.contract.json';
  const outPath = process.argv[3] || 'generated-examples/auth/auth.generated.js';

  const contractRaw = fs.readFileSync(contractPath, 'utf8');
  const contract = JSON.parse(contractRaw);
  
  generateAuth(contract, outPath);
}

import { fileURLToPath } from 'url';
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  runCLI();
}
